   1: import type { CompilationResult, OpportunityInput, OpportunitySpec } from '@openfons/contracts';
   2: 
   3: export type ControlApi = {
   4:   createOpportunity: (input: OpportunityInput) => Promise<OpportunitySpec>;
   5:   compileOpportunity: (opportunityId: string) => Promise<CompilationResult>;
   6: };
   7: 
   8: export const createControlApi = (baseUrl: string): ControlApi => ({
   9:   async createOpportunity(input) {
  10:     const response = await fetch(`${baseUrl}/api/v1/opportunities`, {
  11:       method: 'POST',
  12:       headers: {
  13:         'Content-Type': 'application/json'
  14:       },
  15:       body: JSON.stringify(input)
  16:     });
  17: 
  18:     if (!response.ok) {
  19:       throw new Error('Failed to create opportunity');
  20:     }
  21: 
  22:     const parsed = (await response.json()) as { opportunity: OpportunitySpec };
  23:     return parsed.opportunity;
  24:   },
  25:   async compileOpportunity(opportunityId) {
  26:     const response = await fetch(
  27:       `${baseUrl}/api/v1/opportunities/${opportunityId}/compile`,
  28:       {
  29:         method: 'POST'
  30:       }
  31:     );
  32: 
  33:     if (!response.ok) {
  34:       throw new Error('Failed to compile opportunity');
  35:     }
  36: 
  37:     return (await response.json()) as CompilationResult;
  38:   }
  39: });
