   8: export const createControlApi = (baseUrl: string): ControlApi => ({
   9:   async createOpportunity(input) {
  10:     const response = await fetch(`${baseUrl}/api/v1/opportunities`, {
  11:       method: 'POST',
  12:       headers: {
  13:         'Content-Type': 'application/json'
  14:       },
  15:       body: JSON.stringify(input)
  16:     });
